// src/cli.ts
import { readFileSync } from "node:fs";
var DEFAULT_HOST = "https://cloud.langfuse.com";
var OPENAPI_FILE_URL = new URL("../openapi.yml", import.meta.url);
var LANGFUSE_SKILL_URL = "https://raw.githubusercontent.com/langfuse/skills/main/skills/langfuse/SKILL.md";
var GET_SKILL_FETCH_TIMEOUT_MS = 5000;
var LANGFUSE_FLAGS = new Set([
  "--public-key",
  "--secret-key",
  "--host",
  "--env"
]);
var LANGFUSE_BOOL_FLAGS = new Set(["--refetch-api-spec"]);
function loadEnvFile(filePath) {
  const content = readFileSync(filePath, "utf-8");
  for (const line of content.split(`
`)) {
    const trimmed = line.trim();
    if (!trimmed || trimmed.startsWith("#"))
      continue;
    const eqIdx = trimmed.indexOf("=");
    if (eqIdx === -1)
      continue;
    const key = trimmed.slice(0, eqIdx).trim();
    let val = trimmed.slice(eqIdx + 1).trim();
    if (val.startsWith('"') && val.endsWith('"') || val.startsWith("'") && val.endsWith("'")) {
      val = val.slice(1, -1);
    }
    process.env[key] = val;
  }
}
async function loadMain() {
  const specliEntry = import.meta.resolve("specli");
  const cliMainUrl = new URL("cli/main.js", specliEntry);
  const mod = await import(cliMainUrl.href);
  return mod.main;
}
async function getSpecText(params) {
  if (params.refetch) {
    const specUrl = `${params.host}/generated/api/openapi.yml`;
    return fetchText(specUrl, "spec");
  }
  return readFileSync(OPENAPI_FILE_URL, "utf-8");
}
async function fetchText(url, label, options) {
  const resp = await fetch(url, {
    signal: typeof options?.timeoutMs === "number" ? AbortSignal.timeout(options.timeoutMs) : undefined
  });
  if (!resp.ok) {
    throw new Error(`Failed to fetch ${label} from ${url}: ${resp.status} ${resp.statusText}`);
  }
  return resp.text();
}
async function getSkillText() {
  return fetchText(LANGFUSE_SKILL_URL, "skill", {
    timeoutMs: GET_SKILL_FETCH_TIMEOUT_MS
  });
}
function printGetSkillFetchError(err) {
  const reason = err instanceof Error ? err.message : String(err);
  process.stderr.write(`Failed to fetch the latest Langfuse skill from GitHub.
This environment may block direct GitHub access.

Download the skill manually from:
  ${LANGFUSE_SKILL_URL}

Then add the downloaded SKILL.md to your agent context manually.

Original error: ${reason}
`);
}
async function run(argv) {
  const extracted = {};
  const boolFlags = {};
  const passthrough = [argv[0], argv[1]];
  let i = 2;
  while (i < argv.length) {
    if (LANGFUSE_FLAGS.has(argv[i]) && i + 1 < argv.length) {
      const key = argv[i].replace(/^--/, "");
      extracted[key] = argv[i + 1];
      i += 2;
    } else if (LANGFUSE_BOOL_FLAGS.has(argv[i])) {
      const key = argv[i].replace(/^--/, "");
      boolFlags[key] = true;
      i++;
    } else {
      passthrough.push(argv[i]);
      i++;
    }
  }
  if (extracted["env"]) {
    loadEnvFile(extracted["env"]);
  }
  const publicKey = extracted["public-key"] ?? process.env.LANGFUSE_PUBLIC_KEY;
  const secretKey = extracted["secret-key"] ?? process.env.LANGFUSE_SECRET_KEY;
  const host = (extracted["host"] ?? process.env.LANGFUSE_BASE_URL ?? process.env.LANGFUSE_HOST ?? DEFAULT_HOST).replace(/\/$/, "");
  const subcommand = passthrough[2];
  if (subcommand === "api") {
    passthrough.splice(2, 1);
    return runApi({ passthrough, boolFlags, publicKey, secretKey, host });
  }
  if (subcommand === "get-skill") {
    try {
      process.stdout.write(await getSkillText());
    } catch (err) {
      printGetSkillFetchError(err);
      process.exitCode = 1;
    }
    return;
  }
  printHelp();
}
function printHelp() {
  console.log(`langfuse-cli — Interact with Langfuse from the command line

Usage: langfuse [options] <command>

Commands:
  api                     Interact with the Langfuse REST API
  get-skill               Print the latest Langfuse skill from GitHub

Options:
  --public-key <key>      Langfuse public key (or LANGFUSE_PUBLIC_KEY)
  --secret-key <key>      Langfuse secret key (or LANGFUSE_SECRET_KEY)
  --host <url>            Langfuse host (or LANGFUSE_HOST/LANGFUSE_BASE_URL, default: ${DEFAULT_HOST})
  --env <path>       Load env vars from file
  --refetch-api-spec      Fetch latest API spec instead of bundled

Examples:
  langfuse api __schema                              List all available resources
  langfuse api <resource> --help                     Show actions for a resource
  langfuse api traces list --limit 10                List traces
  langfuse api prompts list                          List prompts
  langfuse api scores create --name quality \\
    --traceId <id> --value 0.9                       Create a score
  langfuse api datasets create --name my-dataset     Create a dataset`);
}
function printApiHelp(resources) {
  const sorted = [...resources].sort();
  console.log(`Usage: langfuse api [options] <resource> <action>

Langfuse API Resources:
${sorted.map((r) => `  ${r}`).join(`
`)}

Commands:
  __schema                Show API spec metadata
  <resource> --help       Show actions for a resource
  <resource> <action> --help  Show options for an action

Options:
  --json                  Output as JSON
  --curl                  Preview curl command without executing
  -h, --help              Show help

Workflow:
  1) langfuse api __schema
  2) langfuse api <resource> --help
  3) langfuse api <resource> <action> --help
  4) langfuse api <resource> <action> [options]`);
}
async function getResources(specText) {
  const main = await loadMain();
  const chunks = [];
  const origWrite = process.stdout.write.bind(process.stdout);
  process.stdout.write = (chunk) => {
    chunks.push(String(chunk));
    return true;
  };
  try {
    await main(["node", "langfuse", "__schema", "--json"], {
      cliName: "langfuse api",
      auth: "BasicAuth",
      embeddedSpecText: specText
    });
  } finally {
    process.stdout.write = origWrite;
  }
  const output = JSON.parse(chunks.join(""));
  return (output.data?.resources ?? []).map((r) => r.name);
}
async function runApi(params) {
  const { passthrough, boolFlags, publicKey, secretKey, host } = params;
  const specText = await getSpecText({
    refetch: boolFlags["refetch-api-spec"] ?? false,
    host
  });
  const args = passthrough.slice(2);
  if (args.length === 0 || args.length === 1 && (args[0] === "--help" || args[0] === "-h")) {
    printApiHelp(await getResources(specText));
    return;
  }
  const specliArgv = [...passthrough];
  const inject = ["--server", host];
  if (publicKey)
    inject.push("--username", publicKey);
  if (secretKey)
    inject.push("--password", secretKey);
  specliArgv.splice(2, 0, ...inject);
  const main = await loadMain();
  await main(specliArgv, {
    cliName: "langfuse api",
    auth: "BasicAuth",
    embeddedSpecText: specText
  });
}
export {
  run
};

import { isJsonSchema } from "../core/types.js";
import { getSchemaEnumStrings, getSchemaFormat, getSchemaType, } from "./schema-shape.js";
function getRequestBody(op) {
    return op.requestBody;
}
export function deriveRequestBodyInfo(op) {
    const rb = getRequestBody(op);
    if (!rb)
        return undefined;
    const content = [];
    for (const contentType of rb.contentTypes) {
        const schema = rb.schemasByContentType[contentType];
        content.push({
            contentType,
            required: rb.required,
            schemaType: getSchemaType(schema),
            schemaFormat: getSchemaFormat(schema),
            schemaEnum: getSchemaEnumStrings(schema),
        });
    }
    content.sort((a, b) => a.contentType.localeCompare(b.contentType));
    const hasJson = content.some((c) => c.contentType.includes("json"));
    const hasFormUrlEncoded = content.some((c) => c.contentType === "application/x-www-form-urlencoded");
    const hasMultipart = content.some((c) => c.contentType.startsWith("multipart/"));
    const bodyFlags = ["--data", "--file"]; // always available when requestBody exists
    const preferredContentType = content.find((c) => c.contentType === "application/json")?.contentType ??
        content.find((c) => c.contentType.includes("json"))?.contentType ??
        content[0]?.contentType;
    const preferredSchema = preferredContentType
        ? rb.schemasByContentType[preferredContentType]
        : undefined;
    return {
        required: rb.required,
        content,
        hasJson,
        hasFormUrlEncoded,
        hasMultipart,
        bodyFlags,
        preferredContentType,
        preferredSchema: isJsonSchema(preferredSchema)
            ? preferredSchema
            : undefined,
    };
}

import { Command } from "commander";
import { generateBodyFlags } from "./body-flags.js";
import { executeAction } from "./execute.js";
import { coerceArrayInput, coerceValue } from "./validate/index.js";
/**
 * Format help output that is clear for both humans and AI agents.
 * Groups options into Required, Optional, and Global sections.
 */
function formatCustomHelp(cmd, action, operationFlags, bodyFlagDefs) {
    const lines = [];
    const cmdName = cmd.name();
    const parentName = cmd.parent?.name() ?? "";
    const fullCmd = parentName ? `${parentName} ${cmdName}` : cmdName;
    // Usage line
    const positionals = action.positionals.map((p) => `<${p.name}>`).join(" ");
    const usageSuffix = positionals ? ` ${positionals}` : "";
    lines.push(`Usage: ${fullCmd}${usageSuffix} [options]`);
    lines.push("");
    // Description
    const desc = action.summary ?? action.description ?? `${action.method} ${action.path}`;
    lines.push(desc);
    lines.push("");
    // Collect all options into categories
    const requiredOpts = [];
    const optionalOpts = [];
    // Format a single option line
    const formatOpt = (flag, type, desc, required) => {
        const typeStr = type === "boolean" ? "" : ` <${type}>`;
        const reqMarker = required ? " (required)" : "";
        return `  ${flag}${typeStr}${reqMarker}\n      ${desc}`;
    };
    // Operation flags (query/header/path params)
    for (const f of operationFlags) {
        const type = f.type === "array" ? `${f.itemType ?? "string"}[]` : f.type;
        const line = formatOpt(f.flag, type, f.description ?? `${f.in} parameter`, f.required);
        if (f.required) {
            requiredOpts.push(line);
        }
        else {
            optionalOpts.push(line);
        }
    }
    // Body flags
    for (const def of bodyFlagDefs) {
        const line = formatOpt(def.flag, def.type, def.description, def.required);
        if (def.required) {
            requiredOpts.push(line);
        }
        else {
            optionalOpts.push(line);
        }
    }
    // Required options section
    if (requiredOpts.length > 0) {
        lines.push("Required:");
        lines.push(...requiredOpts);
        lines.push("");
    }
    // Optional options section
    if (optionalOpts.length > 0) {
        lines.push("Options:");
        lines.push(...optionalOpts);
        lines.push("");
    }
    // Global options (always available)
    lines.push("Global:");
    lines.push("  --curl\n      Print curl command instead of executing");
    lines.push("  --json\n      Output response as JSON");
    lines.push("  --server <url>\n      Override the API server URL");
    lines.push("  --bearer-token <token>\n      Provide auth token (or use 'login' command)");
    lines.push("  -h, --help\n      Show this help message");
    lines.push("");
    return lines.join("\n");
}
export function addGeneratedCommands(program, context) {
    for (const resource of context.commands.resources) {
        const resourceCmd = program
            .command(resource.resource)
            .description(`Operations for ${resource.resource}`);
        for (const action of resource.actions) {
            const cmd = resourceCmd.command(action.action);
            cmd.description(action.summary ??
                action.description ??
                `${action.method} ${action.path}`);
            for (const pos of action.positionals) {
                cmd.argument(`<${pos.name}>`, pos.description);
            }
            for (const flag of action.flags) {
                const opt = flag.flag;
                const desc = flag.description ?? `${flag.in} parameter`;
                if (flag.type === "boolean") {
                    cmd.option(opt, desc);
                    continue;
                }
                const isArray = flag.type === "array";
                const itemType = flag.itemType ?? "string";
                const flagType = isArray ? itemType : flag.type;
                const parser = (raw) => coerceValue(raw, flagType);
                if (isArray) {
                    const key = `${opt} <value>`;
                    cmd.option(key, desc, (value, prev) => {
                        const next = [...(prev ?? [])];
                        // Allow `--tags a,b` and `--tags '["a","b"]'` to expand.
                        const items = coerceArrayInput(value, itemType);
                        for (const item of items) {
                            next.push(item);
                        }
                        return next;
                    });
                    continue;
                }
                const key = `${opt} <value>`;
                if (flag.required)
                    cmd.requiredOption(key, desc, parser);
                else
                    cmd.option(key, desc, parser);
            }
            // Collect reserved flags: operation params + --curl
            const operationFlagSet = new Set(action.flags.map((f) => f.flag));
            const reservedFlags = new Set([...operationFlagSet, "--curl"]);
            // Only --curl is a built-in flag (for debugging)
            if (!operationFlagSet.has("--curl")) {
                cmd.option("--curl", "Print curl command without sending");
            }
            // Track body flag definitions for this action
            let bodyFlagDefs = [];
            if (action.requestBody) {
                // Generate body flags from schema (recursive with dot notation)
                // Pass reserved flags to avoid conflicts with operation params and --curl
                bodyFlagDefs = generateBodyFlags(action.requestBodySchema, reservedFlags);
                for (const def of bodyFlagDefs) {
                    if (def.type === "boolean") {
                        cmd.option(def.flag, def.description);
                    }
                    else {
                        cmd.option(`${def.flag} <value>`, def.description);
                    }
                }
            }
            // Custom help output for better agent/human readability
            cmd.configureHelp({
                formatHelp: () => formatCustomHelp(cmd, action, action.flags, bodyFlagDefs),
            });
            // Commander passes positional args and then the Command instance as last arg.
            cmd.action(async (...args) => {
                const command = args[args.length - 1];
                const positionalValues = args.slice(0, -1).map((v) => String(v));
                if (!(command instanceof Command)) {
                    throw new Error("Unexpected commander action signature");
                }
                const globals = command.optsWithGlobals();
                const local = command.opts();
                await executeAction({
                    action,
                    positionalValues,
                    flagValues: local,
                    globals,
                    servers: context.servers,
                    authSchemes: context.authSchemes,
                    specId: context.specId,
                    embeddedDefaults: context.embeddedDefaults,
                    bodyFlagDefs,
                    resourceName: resource.resource,
                });
            });
        }
    }
}

/**
 * Body flag generation and parsing utilities.
 *
 * Generates CLI flags from JSON schema properties and parses
 * dot-notation flags back into nested objects.
 */
/**
 * Generate flag definitions from a JSON schema.
 * Recursively handles nested objects using dot notation.
 */
export function generateBodyFlags(schema, reservedFlags) {
    if (!schema || schema.type !== "object" || !schema.properties) {
        return [];
    }
    const flags = [];
    const requiredSet = new Set(schema.required ?? []);
    collectFlags(schema.properties, [], requiredSet, flags, reservedFlags);
    return flags;
}
function collectFlags(properties, pathPrefix, requiredAtRoot, out, reservedFlags) {
    for (const [name, propSchema] of Object.entries(properties)) {
        if (!name || typeof name !== "string")
            continue;
        if (!propSchema || typeof propSchema !== "object")
            continue;
        const path = [...pathPrefix, name];
        const flagName = `--${path.join(".")}`;
        // Skip if this flag would conflict with an operation parameter
        if (reservedFlags.has(flagName))
            continue;
        const t = propSchema.type;
        if (t === "object" && propSchema.properties) {
            // Recurse into nested object
            const nestedRequired = new Set(propSchema.required ?? []);
            collectFlags(propSchema.properties, path, nestedRequired, out, reservedFlags);
        }
        else if (t === "string" ||
            t === "number" ||
            t === "integer" ||
            t === "boolean") {
            // Leaf property - generate a flag
            const isRequired = pathPrefix.length === 0 ? requiredAtRoot.has(name) : false;
            out.push({
                flag: flagName,
                path,
                type: t,
                description: propSchema.description ?? `Body field '${path.join(".")}'`,
                required: isRequired,
            });
        }
        // Skip arrays and other complex types for now
    }
}
/**
 * Parse flag values with dot notation into a nested object.
 *
 * Example:
 *   { "address.street": "123 Main", "address.city": "NYC", "name": "Ada" }
 * Becomes:
 *   { address: { street: "123 Main", city: "NYC" }, name: "Ada" }
 */
export function parseDotNotationFlags(flagValues, flagDefs) {
    const result = {};
    for (const def of flagDefs) {
        // Commander keeps dots in option names: --address.street -> "address.street"
        const dotKey = def.path.join(".");
        const value = flagValues[dotKey];
        if (value === undefined)
            continue;
        setNestedValue(result, def.path, value, def.type);
    }
    return result;
}
/**
 * Set a value at a nested path, creating intermediate objects as needed.
 */
function setNestedValue(obj, path, value, type) {
    let current = obj;
    for (let i = 0; i < path.length - 1; i++) {
        const key = path[i];
        if (!(key in current) || typeof current[key] !== "object") {
            current[key] = {};
        }
        current = current[key];
    }
    const finalKey = path[path.length - 1];
    // Coerce value based on type
    if (type === "boolean") {
        current[finalKey] = true;
    }
    else if (type === "integer") {
        current[finalKey] = Number.parseInt(String(value), 10);
    }
    else if (type === "number") {
        current[finalKey] = Number(String(value));
    }
    else {
        current[finalKey] = String(value);
    }
}
/**
 * Check if all required fields are present.
 * Returns list of missing field paths.
 */
export function findMissingRequired(flagValues, flagDefs) {
    const missing = [];
    for (const def of flagDefs) {
        if (!def.required)
            continue;
        // Commander keeps dots in option names: --address.street -> "address.street"
        const dotKey = def.path.join(".");
        if (flagValues[dotKey] === undefined) {
            missing.push(dotKey);
        }
    }
    return missing;
}

